const raw = $input.first().json;
const incoming = raw.body || raw;
const config = {
  SUPABASE_URL: 'YOUR_SUPABASE_URL',
  SUPABASE_SERVICE_KEY: 'YOUR_SUPABASE_SERVICE_KEY',
  ANTHROPIC_API_KEY: 'YOUR_ANTHROPIC_API_KEY',
  SERPER_API_KEY: 'YOUR_SERPER_API_KEY',
  MODEL_MAIN: 'claude-sonnet-4-6',
  MODEL_FAST: 'claude-haiku-4-5-20251001',
  GRYNOW_WEBSITE_ID: 'YOUR_GRYNOW_WEBSITE_ID',
  MYWALL_WEBSITE_ID: 'YOUR_MYWALL_WEBSITE_ID',
  IGYGROW_WEBSITE_ID: 'YOUR_IGYGROW_WEBSITE_ID',
  DEPLOY_WEBHOOK_URL: 'http://host.docker.internal:7331/deploy',
  DEPLOY_TOKEN: 'YOUR_DEPLOY_TOKEN',
  DEFAULT_THUMBNAIL_URL: '',
};
return [{ json: { ...config, ...incoming } }];

const fetch=(u,o={})=>new Promise((res,rej)=>{const iH=u.startsWith('https');const lib=require(iH?'https':'http');const m=u.match(/^https?:\/\/([^/:]+)(?::(\d+))?(\/[^?#]*)?(\?[^#]*)?/);if(!m)return rej(new Error('Bad URL: '+u));const body=o.body||null;const req=lib.request({hostname:m[1],port:m[2]?+m[2]:(iH?443:80),path:(m[3]||'/')+(m[4]||''),method:o.method||'GET',headers:{...(o.headers||{}),...(body?{'Content-Length':Buffer.byteLength(body)}:{})}},r=>{let d='';r.on('data',c=>d+=c);r.on('end',()=>res({ok:r.statusCode<300,status:r.statusCode,json:()=>Promise.resolve(JSON.parse(d||'null')),text:()=>Promise.resolve(d)}));});req.on('error',rej);if(body)req.write(body);req.end();});

const cfg = $('Config').first().json;

// ── shared helpers ──────────────────────────────────────────────────────────
const sbUrl = cfg.SUPABASE_URL, sbKey = cfg.SUPABASE_SERVICE_KEY;
const sbH = { apikey: sbKey, Authorization: 'Bearer ' + sbKey, 'Content-Type': 'application/json' };
async function sbGet(p){ const r = await fetch(sbUrl+'/rest/v1/'+p,{headers:{apikey:sbKey,Authorization:'Bearer '+sbKey}}); return r.ok?r.json():[]; }
async function sbPatch(t,f,b){ await fetch(sbUrl+'/rest/v1/'+t+'?'+f,{method:'PATCH',headers:sbH,body:JSON.stringify(b)}); }
async function sbInsert(t,b){ const r = await fetch(sbUrl+'/rest/v1/'+t,{method:'POST',headers:{...sbH,Prefer:'return=representation'},body:JSON.stringify(b)}); return r.json(); }

async function claude(system,user,maxTokens,model){
  let last;
  for(let i=0;i<3;i++){
    try{
      const r = await fetch('https://api.anthropic.com/v1/messages',{method:'POST',headers:{'x-api-key':cfg.ANTHROPIC_API_KEY,'anthropic-version':'2023-06-01','Content-Type':'application/json'},body:JSON.stringify({model:model||cfg.MODEL_MAIN||'claude-sonnet-4-6',max_tokens:maxTokens||4096,system,messages:[{role:'user',content:user}]})});
      const d = await r.json();
      if(d.content&&d.content[0])return d.content[0].text;
      last = new Error('Claude error: '+JSON.stringify(d).slice(0,300));
    }catch(e){ last = e; }
    await new Promise(res=>setTimeout(res,800*(i+1)));
  }
  throw last;
}
function parseJSON(text){
  try{ const m = text.match(/\`\`\`json\s*([\s\S]*?)\`\`\`/) || text.match(/([\[{][\s\S]*[\]}])/); return JSON.parse(m?m[1]:text); }
  catch(e){ return { _parse_error:true, raw:String(text).substring(0,300) }; }
}
// Serper (Google SERP). Degrades gracefully to empty data if no key / on error,
// so the SEO Agent still runs (LLM-only) rather than failing the pipeline.
async function serper(q){
  if(!cfg.SERPER_API_KEY || String(cfg.SERPER_API_KEY).startsWith('YOUR_')) return {organic:[],peopleAlsoAsk:[],relatedSearches:[]};
  try{
    const r = await fetch('https://google.serper.dev/search',{method:'POST',headers:{'X-API-KEY':cfg.SERPER_API_KEY,'Content-Type':'application/json'},body:JSON.stringify({q,gl:'in',num:10})});
    return (await r.json()) || {};
  }catch(e){ return {organic:[],peopleAlsoAsk:[],relatedSearches:[],_serper_error:e.message}; }
}

// ── intake normalisation (goal-mode: just a keyword + a website) ─────────────
const keyword      = (cfg.keyword || cfg.goal || cfg.topic || '').trim();
const goal         = (cfg.goal || ('rank for ' + keyword)).trim();
const website_slug = cfg.website_slug || 'grynow';
const content_type = cfg.content_type || 'blog';
let   placement    = cfg.placement || 'off-page';
if(!keyword) throw new Error('Autopilot requires a keyword or goal.');

const SITE_MAP = {
  grynow:  { id: cfg.GRYNOW_WEBSITE_ID,  name: 'GryNow',  url: 'https://grynow.in' },
  mywall:  { id: cfg.MYWALL_WEBSITE_ID,  name: 'MyWall',  url: 'https://mywall.me' },
  igygrow: { id: cfg.IGYGROW_WEBSITE_ID, name: 'Igygrow', url: 'https://www.igygrow.com' },
};
const site = SITE_MAP[website_slug] || SITE_MAP.grynow;
const websiteId = site.id, websiteName = site.name, websiteUrl = cfg.website_url || site.url;

// ── site context: knowledge base + real internal links ───────────────────────
const [kbData, ilData] = await Promise.all([
  sbGet('knowledge_base?select=category,content&or=(website_id.eq.'+websiteId+',website_id.is.null)').catch(()=>[]),
  sbGet('internal_links?select=url,title,h1&website_id=eq.'+websiteId+'&limit=40').catch(()=>[]),
]);
const kb = {}; (Array.isArray(kbData)?kbData:[]).forEach(d=>{ kb[d.category]=d.content; });
const businessKnowledge = [kb['business-overview'], kb['site-overview']].filter(Boolean).join('\n\n') || 'Digital platform.';
const brandVoice = kb['brand-voice'] || 'Professional, clear, value-focused.';
const competitorsKb = kb['competitors'] || 'None on file.';
const internalList = (Array.isArray(ilData)?ilData:[]).map(l=>'- '+(l.title||l.h1||'(page)')+' — '+l.url).join('\n') || 'No internal pages on file yet.';

// ══════════════════════ STAGE 0 — SEO AGENT (Senior SEO Lead) ════════════════
const serpRaw = await serper(keyword);
const serpData = {
  organic: (serpRaw.organic||[]).slice(0,10).map(o=>({title:o.title,link:o.link,snippet:o.snippet})),
  peopleAlsoAsk: (serpRaw.peopleAlsoAsk||[]).map(p=>p.question).filter(Boolean),
  relatedSearches: (serpRaw.relatedSearches||[]).map(r=>r.query).filter(Boolean),
};

const seoSys = 'You are a Senior SEO Lead. You make EVERY strategic SEO decision before any content is written. Downstream agents consume your brief verbatim and must never infer anything you omit. Ground keywords/competitors/gaps/PAA/related in the SERP data; ground business facts in the business knowledge. Never invent statistics, competitor claims, or internal URLs. Use ONLY the provided internal pages for internal links. Respect: meta title <=60 chars, meta description <=155 chars, kebab-case slug, one H1, logical H2>H3. Return ONLY valid JSON.';
const seoMsg = 'Business goal: '+goal+'\nSeed keyword: '+keyword+'\nWebsite: '+websiteName+' ('+websiteUrl+'), slug '+website_slug+'\nPlacement: '+placement+' (on-page = brand says "we"; off-page = third party)\nContent type: '+content_type+'\n\nBusiness & site knowledge (do not contradict):\n'+businessKnowledge+'\n\nBrand voice: '+brandVoice+'\nKnown competitors: '+competitorsKb+'\n\nExisting internal pages (use ONLY these real URLs for internal links):\n'+internalList+'\n\nLive SERP data for the seed keyword:\n'+JSON.stringify(serpData,null,2)+'\n\nReturn ONLY JSON in EXACTLY this shape:\n{"goal":"","primary_keyword":"","placement":"'+placement+'","content_type":"'+content_type+'","business":{"model":"","products":"","icp":"","audience":"","positioning":"","industry":""},"website_understanding":{"fits_cluster":"","reinforces":"","notes":""},"keywords":{"primary":"","secondary":[],"long_tail":[],"semantic":[],"questions":[],"commercial":[],"informational":[]},"serp":{"intent":"informational","top_competitors":[{"url":"","strengths":[],"weaknesses":[],"missing":[],"opportunity":""}],"content_gaps":[],"featured_snippet":{"opportunity":"","format":"paragraph"},"paa":[],"related_searches":[]},"topical_authority":{"pillar":"","cluster":[],"supporting_articles":[]},"links":{"internal":[{"url":"","anchor":"","placement":""}],"outbound":[{"url":"","anchor":"","placement":""}]},"content_plan":{"angle":"","h1":"","outline":[{"level":"h2","text":"","notes":""}],"faqs":[{"q":"","a_hint":""}],"cta":{"text":"","placement":"end"}},"metadata":{"meta_title":"","meta_description":"","slug":"","canonical":"","og":{"title":"","description":"","type":"article","image":""},"twitter":{"card":"summary_large_image","title":"","description":""}},"schema":["Article","BlogPosting","FAQPage","BreadcrumbList"]}';

const seo_brief = parseJSON(await claude(seoSys, seoMsg, 8000));
if(seo_brief._parse_error) throw new Error('SEO Agent returned unparseable brief: '+seo_brief.raw);
placement = seo_brief.placement || placement;
const bm = seo_brief.metadata || {};
const bp = seo_brief.content_plan || {};
const bk = seo_brief.keywords || {};

// derive request fields from the brief
const topic = bp.h1 || keyword;
const keywordsArr = [bk.primary, ...(bk.secondary||[]), ...(bk.long_tail||[])].filter(Boolean).slice(0,25);

// create the content_requests row now that the SEO strategy exists
const reqRows = await sbInsert('content_requests', {
  website_id: websiteId, placement, content_type, topic,
  keywords: keywordsArr.length?keywordsArr:[keyword], goal, seo_brief,
  status: 'researching',
});
const requestId = (Array.isArray(reqRows)&&reqRows[0]&&reqRows[0].id) || null;
if(!requestId) throw new Error('Failed to create content_requests row: '+JSON.stringify(reqRows).slice(0,300));

// outline seed from the brief (H1 + the SEO agent's H2/H3 plan)
const outlineSeed = ['# '+(bp.h1||topic)].concat((bp.outline||[]).map(o=>((o.level==='h3')?'### ':'## ')+o.text+(o.notes?(' — '+o.notes):''))).join('\n') || 'Propose a sensible structure.';

// ══════════════════════ STAGE 1 — CONTENT RESEARCHER ═════════════════════════
const researchSys = 'You are a Senior Content Researcher. You prepare structured research notes a writer will expand — you do NOT write the article and you do NOT do SEO (that is already decided). For each outline section: explain the concept simply; gather key facts/insights; list reader questions; find examples/use-cases; note supporting data; note misconceptions; list subtopics; write writer notes. Return ONLY valid JSON.';
const researchMsg = 'Topic: '+topic+'\nContent type: '+content_type+'\nTarget audience: '+((seo_brief.business||{}).audience||'General readers')+'\nSearch intent: '+((seo_brief.serp||{}).intent||'informational')+'\nBusiness/site knowledge (factual grounding — do not contradict):\n'+businessKnowledge+'\nOutline (from the SEO brief):\n'+outlineSeed+'\n\nReturn ONLY JSON: {"target_audience":"","search_intent":"informational","sections":[{"heading":"","key_points":[],"reader_questions":[],"examples":[],"supporting_data":[],"misconceptions":[],"subtopics":[],"writer_notes":""}]}';
const researchNotes = parseJSON(await claude(researchSys, researchMsg, 4096));
await sbPatch('content_requests','id=eq.'+requestId, { research_brief: researchNotes, status: 'strategizing' });

// ══════════════════════ STAGE 2 — CONTENT PLANNER ═══════════════════════════
const toneHint = placement==='on-page' ? 'FIRST PERSON — the brand speaks as "we"/"our".' : 'THIRD PERSON — refer to the brand by name, never "we".';
const planSys = 'You are a Senior Content Planner. Turn the research notes into a firm editorial plan the writer follows exactly. The SEO strategy (outline, intent, angle) is ALREADY decided in the brief — CONFIRM and refine it for content quality; do not re-do SEO. Return ONLY valid JSON.';
const planMsg = content_type+' | '+placement+' -> '+toneHint+'\nTopic: '+topic+'\nSEO angle: '+(bp.angle||'')+'\nOutline (authoritative, from SEO brief):\n'+outlineSeed+'\n\nResearch Notes:\n'+JSON.stringify(researchNotes).slice(0,6000)+'\n\nReturn ONLY JSON: {"target_audience":"","search_intent":"informational","word_count_target":0,"word_count_rationale":"","depth":"in-depth","depth_rationale":"","tone":"","content_angle":"","outline":[{"level":"h1","text":"","notes":""}],"cta_text":"","cta_placement":"end","special_instructions":""}';
const contentPlan = parseJSON(await claude(planSys, planMsg, 4096));
await sbPatch('content_requests','id=eq.'+requestId, { strategy_brief: contentPlan, status: 'drafting' });

// ══════════════════════ STAGE 3 — CONTENT WRITER ════════════════════════════
const toneD = placement==='on-page'
  ? 'FIRST PERSON — You ARE '+websiteName+'. Use "we","our","us". Never third person.'
  : 'THIRD PERSON — Authoritative writer. Refer to '+websiteName+' by name. NEVER "we"/"our".';
const internalLinksStr = ((seo_brief.links||{}).internal||[]).map(l=>'- ['+l.anchor+']('+l.url+') — place: '+(l.placement||'where relevant')).join('\n') || 'None.';
const outboundLinksStr = ((seo_brief.links||{}).outbound||[]).map(l=>'- ['+l.anchor+']('+l.url+') — place: '+(l.placement||'where relevant')).join('\n') || 'None.';
const faqStr = (bp.faqs||[]).map(f=>'- '+f.q+(f.a_hint?(' (hint: '+f.a_hint+')'):'')).join('\n') || 'None.';
const kwStr = [bk.primary,...(bk.secondary||[]),...(bk.long_tail||[])].filter(Boolean).join(', ');

const writerSys = 'You are a Senior Content Writer for '+websiteName+'.\n\nTONE: '+toneD+'\n\nBusiness: '+businessKnowledge+'\nBrand Voice: '+brandVoice+'\n\nFollow the outline exactly. Expand the research notes into clear, engaging, EEAT-aligned content. Short scannable paragraphs, bullets/lists where useful, logical flow, no repetition. Match the brand voice. Grounding: use only facts/data/examples in the research notes — never invent sources, numbers or claims. Naturally weave in the target keywords (do NOT keyword-stuff). Insert the given internal and outbound links as real Markdown links with the exact anchor text, placed where indicated. End with an FAQ section (H2 "FAQs") answering the given questions, and include the CTA at its placement. Output ONLY the article in Markdown starting with the H1 — no metadata, notes, or commentary.';
const writerMsg = 'Topic: '+topic+'\nContent type: '+content_type+' | Placement: '+placement+'\nTarget audience: '+(contentPlan.target_audience||(seo_brief.business||{}).audience||'General readers')+'\nSearch intent: '+(contentPlan.search_intent||(seo_brief.serp||{}).intent||'informational')+'\nTarget length: '+(contentPlan.word_count_target||1200)+' words (+-10%) | Depth: '+(contentPlan.depth||'in-depth')+'\nContent angle: '+(contentPlan.content_angle||bp.angle||'')+'\nCTA: '+((bp.cta||{}).text||contentPlan.cta_text||'')+' (placement: '+((bp.cta||{}).placement||contentPlan.cta_placement||'end')+')\nKeywords to weave in naturally: '+kwStr+'\nInternal links to insert:\n'+internalLinksStr+'\nOutbound links to insert:\n'+outboundLinksStr+'\nFAQs to answer:\n'+faqStr+'\nSpecial instructions: '+(contentPlan.special_instructions||'None')+'\n\nOutline (follow exactly):\n'+outlineSeed+'\n\nResearch Notes:\n'+JSON.stringify(researchNotes).slice(0,8000)+'\n\nWrite the full '+content_type+' now. Output ONLY Markdown starting with the H1.';
const draftMd = (await claude(writerSys, writerMsg, 8096)).trim();
await sbPatch('content_requests','id=eq.'+requestId, { status: 'humanizing' });

// ══════════════════════ STAGE 4 — HUMANIZER & AI-DETECTION ═══════════════════
const humanSys = 'You are a Senior Editor. Make this AI-drafted article read like an experienced human wrote it, WITHOUT changing meaning or SEO. Remove AI tells (formulaic openers, "In conclusion", "It is important to note", "Not only... but also", over-hedging). Vary sentence rhythm (burstiness). Improve transitions and vocabulary variety. Tighten filler. HARD CONSTRAINTS — never break: preserve every fact/number/name/quote; keep all keywords present and naturally placed; keep the H1 and full H2/H3 hierarchy (no adding/dropping/reordering/renaming sections); preserve EVERY Markdown link and its anchor text exactly; preserve lists/tables/code/blockquotes; stay within +-10% of the original length. You are an editor, not an author — do not add information. Output ONLY the improved Markdown starting with the H1.';
const humanMsg = 'Primary keyword: '+(bk.primary||keyword)+'\nBrand voice: '+brandVoice+'\nPlacement: '+placement+'\n\nArticle:\n'+draftMd;
let contentMd = (await claude(humanSys, humanMsg, 8096)).trim();
if(!contentMd || contentMd.length < draftMd.length*0.5) contentMd = draftMd; // safety: never ship an empty/gutted humanizer output

const wordCount = (contentMd.replace(/[#>*_\`\[\]()\-]/g,' ').match(/\b[\w']+\b/g)||[]).length;

// ── save the version (draft; deploy marks it published) ──────────────────────
const verRows = await sbInsert('content_versions', {
  request_id: requestId, version_number: 1, content_markdown: contentMd, word_count: wordCount, status: 'draft',
});
const versionId = (Array.isArray(verRows)&&verRows[0]&&verRows[0].id) || null;
await sbPatch('content_requests','id=eq.'+requestId, { current_version: 1 });

return [{ json: {
  request_id: requestId, version_id: versionId,
  website_slug, website_name: websiteName, website_url: websiteUrl,
  topic, content_type, placement,
  seo_brief, content_markdown: contentMd, word_count: wordCount,
  serper_used: !(serpRaw.organic===undefined) && (serpData.organic.length>0),
}}];

