const cfg = $('Config').first().json;
const r = $json;
const brief = r.seo_brief || {};
const slug = (brief.metadata && brief.metadata.slug) || 'post';
const h1 = (brief.content_plan && brief.content_plan.h1) || r.topic || slug;

// Placeholder: a per-target default (if configured) else the conventional path.
const thumbnail_url = cfg.DEFAULT_THUMBNAIL_URL
  ? cfg.DEFAULT_THUMBNAIL_URL
  : (r.website_url.replace(/\/$/,'') + '/assets/blog/' + slug + '/thumbnail.webp');

return [{ json: { ...r, thumbnail_url, thumbnail_alt: h1, thumbnail_stub: true } }];

