const cfg = $('Config').first().json;
const r = $json;
const brief = r.seo_brief || {};
const md = r.content_markdown;
const meta = brief.metadata || {};
const sbUrl = cfg.SUPABASE_URL, sbKey = cfg.SUPABASE_SERVICE_KEY;
const sbH = { apikey: sbKey, Authorization: 'Bearer '+sbKey, 'Content-Type': 'application/json' };

if(!md) throw new Error('Deploy skipped: no content_markdown');
if(!cfg.DEPLOY_WEBHOOK_URL) throw new Error('Deploy skipped: DEPLOY_WEBHOOK_URL not configured');

await fetch(sbUrl+'/rest/v1/content_requests?id=eq.'+r.request_id,{method:'PATCH',headers:sbH,body:JSON.stringify({status:'deploying'})});

const body = {
  target: r.website_slug,
  markdown: md,
  message: 'Publish: '+(r.topic||'post')+' [autopilot->deploy-agent]',
  // SEO Agent passthrough — deploy-agent uses these verbatim
  slug: meta.slug || undefined,
  metaTitle: meta.meta_title || undefined,
  metaDescription: meta.meta_description || undefined,
  canonical: meta.canonical || undefined,
  schemaTypes: brief.schema || undefined,
  thumbnail: r.thumbnail_url || undefined,
};

const dr = await fetch(cfg.DEPLOY_WEBHOOK_URL,{method:'POST',headers:{'Content-Type':'application/json','x-deploy-token':cfg.DEPLOY_TOKEN},body:JSON.stringify(body)});
const result = await dr.json();
if(!dr.ok || !result || result.ok===false){ throw new Error('Deploy failed: HTTP '+dr.status+' '+JSON.stringify(result).slice(0,300)); }

const publishedUrl = (result.committed && result.committed.url) || result.canonicalUrl || null;

