}
await fetch(sbUrl+'/rest/v1/content_requests?id=eq.'+r.request_id,{method:'PATCH',headers:sbH,body:JSON.stringify({status:'published'})});

return [{ json: { ...r, deployed:true, published_url:publishedUrl, repoPath:result.repoPath||null, canonical:result.canonicalUrl||null } }];

