const cfg = $('Config').first().json;
const r = $json;
const sbUrl = cfg.SUPABASE_URL, sbKey = cfg.SUPABASE_SERVICE_KEY;
const sbH = { apikey: sbKey, Authorization: 'Bearer '+sbKey, 'Content-Type': 'application/json' };
const brief = r.seo_brief || {};

// Resolve website_id from slug map for archive/memory rows.
const websiteId = ({grynow:cfg.GRYNOW_WEBSITE_ID,mywall:cfg.MYWALL_WEBSITE_ID,igygrow:cfg.IGYGROW_WEBSITE_ID}[r.website_slug]) || cfg.GRYNOW_WEBSITE_ID;
const kw = [(brief.keywords||{}).primary, ...((brief.keywords||{}).secondary||[])].filter(Boolean);

// Extract 3-5 reusable positive patterns with the fast model (best-effort).
let patterns = [];
try{
  const hr = await fetch('https://api.anthropic.com/v1/messages',{method:'POST',headers:{'x-api-key':cfg.ANTHROPIC_API_KEY,'anthropic-version':'2023-06-01','Content-Type':'application/json'},body:JSON.stringify({model:cfg.MODEL_FAST||'claude-haiku-4-5-20251001',max_tokens:1024,system:'Extract 3-5 specific, reusable positive writing/SEO patterns from this auto-published, autonomously-approved content. Return ONLY a JSON array.',messages:[{role:'user',content:'Content type: '+r.content_type+'\nPlacement: '+r.placement+'\nTopic: '+r.topic+'\n\nContent (first 2500 chars):\n'+(r.content_markdown||'').substring(0,2500)+'\n\nReturn JSON array: [{"pattern_type":"positive","category":"tone|structure|keywords|formatting|cta","pattern":"specific actionable observation","source":"approved_content","applies_to_placement":"'+r.placement+'","applies_to_content_type":"'+r.content_type+'"}]'}]})});
  const hd = await hr.json();
  const text = hd.content && hd.content[0] ? hd.content[0].text : '[]';
  const m = text.match(/\`\`\`json\s*([\s\S]*?)\`\`\`/) || text.match(/(\[[\s\S]*\])/);
  patterns = JSON.parse(m?m[1]:text);
  if(!Array.isArray(patterns)) patterns=[patterns];
}catch(e){ patterns=[]; }

if(patterns.length){
  await fetch(sbUrl+'/rest/v1/memory_patterns',{method:'POST',headers:sbH,body:JSON.stringify(patterns.map(p=>({...p,website_id:websiteId,frequency:1})))});
}

// Archive the published article (feeds future writer samples + internal links).
await fetch(sbUrl+'/rest/v1/content_archive',{method:'POST',headers:sbH,body:JSON.stringify({content_version_id:r.version_id,request_id:r.request_id,website_id:websiteId,placement:r.placement,content_type:r.content_type,topic:r.topic,keywords:kw,word_count:r.word_count,content_excerpt:(r.content_markdown||'').substring(0,500),full_content:r.content_markdown,published_url:r.published_url||null})});

return [{ json: { done:true, published_url:r.published_url, patterns_saved:patterns.length, request_id:r.request_id } }];
